// Obter as tags do nó anterior
const inputTags = $json["tags"];

// Defina as opções válidas
const validOptions = [
  "2 - Consulta",
  "Status: Contrato Pago"
];

// Verifica se inputTags é um array
let validTag = null;

if (Array.isArray(inputTags)) {
  inputTags.forEach(tag => {
    if (validOptions.includes(tag.name)) {
      validTag = tag.name;  // Armazena a tag válida
    } else if (tag.name.includes('Status')) {
      validTag = tag.name; // Armazena a tag de status
    }
  });
}

// Loop over input items e adiciona um novo campo chamado 'etapa' ao JSON de cada um
var item = $input.item;
var itemJson = item.json; // Acessa o objeto 'json' do item

var etapa = '';
var event_ga4 = '';

// Para o Meta e Tiktok
switch (validTag) { // Usa a tag válida encontrada
  case "2 - Consulta":
    etapa = 'AddToWishlist';
    event_ga4 = 'add_to_wishlist';
    break;
  case "Status: Contrato Pago":
    etapa = 'Purchase';
    event_ga4 = 'purchase';
    break;
  default:
    // Verifica se o nó 'Code' tem dados e se o validTag existe
    if (validTag) {
      etapa = validTag;
    } else {
      etapa = null; // Ou outro valor padrão, como ''
    }
}

// Adiciona a propriedade 'etapa' ao objeto 'json' do item
if (etapa && typeof etapa === 'string' && etapa.includes("Status")) {
  item.json.etapa = '';
  item.json.event_ga4 = '';
} else if (etapa) {
  item.json.etapa = etapa;
  item.json.event_ga4 = event_ga4;
} else {
  item.json.etapa = '';
  item.json.event_ga4 = ''; // Define como vazio se etapa for null ou undefined
}

// Adiciona a validTag ao objeto JSON do item
item.json.validTag = validTag; // Retorna a validTag encontrada

return item.json; // Retorna o objeto JSON atualizado

